const result = $input.first().json.body.result;
const classCounts = result.classCounts || {};
const classSummary = Object.entries(classCounts)
  .map(([k, v]) => `${k}=${v}`)
  .join(' ');
const summary = [
  `✅ Archive metrics backfill tick`,
  `Status: ${result.status}`,
  `Stopped: ${result.stoppedReason}`,
  `DryRun: ${result.dryRun}`,
  `Processed: ${result.processedThisRun} | Synced: ${result.syncedThisRun} | Skipped: ${result.skippedThisRun} | Error: ${result.errorThisRun}`,
  `Candidates scanned: ${result.candidatesScanned}`,
  `Class counts: ${classSummary}`,
  `Stale cleared: ${result.staleCleared}`,
  `Cumulative synced (fetched_count): ${result.totals.fetchedCount}`,
  `Cumulative skipped (upserted_count): ${result.totals.upsertedCount}`
].join('\n');

return [{ json: { summary, result } }];

const statusCode = $input.first().json.statusCode;
const error = $input.first().json.body?.error ?? 'Unknown error';
return [{ json: { error, statusCode, summary: `❌ Archive metrics backfill failed: ${error}` } }];
